var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"일주일 후. 로터스, 아마니 벨리. \\n관리국 부설건물, 접객실 복도.","JPN":"1週間後。ロータス、アマニーバレー。\\n管理局の付属施設、接客室の廊下。","ENG":"A week later. Lotus, Amani Valley.\\nAdministration annexed building, Reception room hallway.","TWN":"一週前。洛德斯，和平谷。\\n管理局附屬大樓，接待室走廊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 연락이 안 되는군.","JPN":"やはり連絡が取れないな。","ENG":"She's not answering as expected.","TWN":"果然聯絡不上。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"오래 기다리게 해서 죄송합니다.","JPN":"長らくお待たせして申し訳ございません。","ENG":"I apologize for keeping you waiting for so long.","TWN":"抱歉，讓你久等了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"최고관리자님의 방문 소식을 시니어님에게 전달드렸습니다만, 만남을 거부했습니다.","JPN":"最高管理者様のご訪問をシニアにお伝えしたのですが、面会を拒否しておりました。","ENG":"I notified our Senior of the Supreme Administrator's visit, but she has refused to meet with you.","TWN":"我已經將最高管理者來訪的消息傳達給了前輩，但她仍然拒絕會面。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"굳이 덧붙이자면. <color=#ffd34c>세상이 멸망해도 만나지 않겠다는 점</color>을 최대한 강조하라더군요.","JPN":"強いて付け加えると。<color=#ffd34c>世界が滅亡しても顔を合わせることはない</color>と最大限強調するようにおっしゃっていました。","ENG":"If I may add. She wanted me to emphasize it by saying that <color=#ffd34c>she wouldn't meet you even if the world was ending</color>.","TWN":"硬要補充的話。她希望我強調<color=#ffd34c>即使世界毀滅也不會見面的</color>這一點。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 말이 농담이 아니라면 마음에 상처를 받겠군.","JPN":"その言葉が冗談でないなら、傷つくな。","ENG":"It would be very hurtful if she wasn't joking.","TWN":"如果你不是在開玩笑，那我可要傷心了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"대신 사과드리겠습니다.","JPN":"代わりにお詫び申し上げます。","ENG":"I apologize on her behalf.","TWN":"我替她向你道歉。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"저희 시니어님은 별 대수롭지 않은 이유로 본인의 책임을 자주 망각하는 분입니다.","JPN":"シニア様はささいなことでご自身の役目を頻繁に忘れる方です。","ENG":"Ms. Isolde is someone who often forgets her responsibilities for insignificant reasons.","TWN":"我們前輩經常因為一些無關緊要的理由而忘記自己的職責。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"사고의 수준이 사탕을 빼앗으면 우는 어린아이나 다름없죠.","JPN":"思考のレベルが、飴を奪われると泣く子どもと同じなのです。","ENG":"Her mentality is no different from a child who cries after someone takes her candy away.","TWN":"她的思考模式有時與被搶了糖果就哭的孩童無異。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠… 부하직원이 그런 표현을 써도 괜찮은 건가? 저 방 안에서 다 듣고 있을 텐데.","JPN":"コホン……部下の職員がそんな表現を使ってもいいのかね？　あの部屋の中ですべて聞いているはずだが。","ENG":"Ahem... Are you sure you are allowed to talk about her like that? I bet she's listening to this conversation from her room right now.","TWN":"咳咳……你作為下屬用那種表達方式真的沒問題嗎？她在那個房間裡應該聽得一清二楚吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"저의 징계나 해고는 걱정거리 축에도 끼지 않습니다.","JPN":"私の懲戒や解雇についてはご心配には及びません。","ENG":"Disciplinary actions or dismissals are not even on the list of concerns.","TWN":"對於我的懲罰或者解雇根本不值得擔心。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"공사 구분도 할 줄 모르는 시니어님의 통찰력이 가져오게 될 로터스의 불운한 미래가 걱정될 따름이죠.","JPN":"公私の区別もつかないシニア様の洞察力がもたらす、ロータスの不運に満ちた未来が心配なだけです。","ENG":"I am just concerned about the unfortunate future that Lotus is facing due to a Senior who cannot keep her personal and professional lives separate.","TWN":"我只會擔心不懂得公私分明的前輩會給洛德斯帶來不幸的未來。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"방금 그 소린 뭐였지?","JPN":"今の音は何だ？","ENG":"What was that sound just now?","TWN":"剛、剛才那個聲音是什麼？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"시니어님은 흥분하면 주먹으로 벽을 때리는 버릇이 있습니다.","JPN":"シニア様は興奮すると拳で壁を叩く癖があります。","ENG":"Ms. Isolde has a habit of punching the wall with her fist when she is frustrated.","TWN":"前輩一激動就有用拳頭錘牆的習慣。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"지난 번처럼 골절된 건 아닐지 걱정이군요.","JPN":"この前のように骨折していないか、心配ですね。","ENG":"I just hope she hasn't broken her fist like last time.","TWN":"希望這次不要像上次那樣骨折了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다행이군. 듣고 있다는 건 적어도 내 방문에 관심은 있다는 뜻이니 말이야.","JPN":"よかった。聞いているということは、少なくとも私の訪問に興味がないわけではないようだから。","ENG":"That's good news. Her eavesdropping means that she's interested in my visit, no?","TWN":"那可真是個好消息。至少這說明她對我的拜訪還是有點興趣的，對嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"원하신다면 제가 멱살이라도 잡아서 끌고 나올까요?","JPN":"お望みなら私が胸ぐらでも掴んで引っ張り出しましょうか？","ENG":"If you want, I could drag her out here.","TWN":"如果你想要的話，我可以幫你把前輩拖出來。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮네. 그럴 필요까진 없어.","JPN":"大丈夫だ。そこまでする必要はない。","ENG":"No, there's no need for that.","TWN":"這個……哈哈，這就不必了吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이졸데 양은 청사진도 없이 다이브 항법장치의 역설계를 통해 그 모방품을 만들어낼 만큼 아주 대단한 천재지.","JPN":"イゾルデ君は青写真がなくてもダイブ航法装置の逆設計を通じてその模倣品を作り上げるほどにとても優れた天才だ。","ENG":"Isolde is a genius who reverse-engineered the dive navigation device and built a replica of it without a blueprint.","TWN":"咳咳……其實，我認為伊索德是個了不起的天才，竟然能在沒有藍圖的情況下，透過逆向設計製造出躍入導航裝置的複製品。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀를 시니어로 세운 것은 그 재능을 높이 샀기 때문일세.","JPN":"彼女をシニアとして立てたのは、その才能を高く評価したからだよ。","ENG":"I appointed her as Senior because I highly valued her talent.","TWN":"我讓她成為Senior完全是因為我看重她的才能。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오늘 내가 이곳에 온 건, 자네의 그 재능이 필요해서야.","JPN":"今日私がここに来たのは、君のその才能が必要だからだ。","ENG":"And I am here today because I need your talents.","TWN":"今天我來這裡，也是因為如此。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이번 부탁을 들어준다면…","JPN":"今回の頼みを聞いてくれるなら……","ENG":"If you grant me this favor...","TWN":"可惜了，如果她能答應這次的請求……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그간 비밀리에 부쳐왔던 이터니움 드라이브의 설계도를 자네에게 제공하도록 하지.","JPN":"今まで内緒にしてきたエタニウムドライブの設計図を君に提供しよう。","ENG":"I'll promise to provide you with the blueprints for the Eternium Drive that I have been keeping a secret.","TWN":"我願意把一直秘密保管的永恆之金驅動器設計圖提供出來。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음…?","JPN":"む……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그 말 진짜야?!","JPN":"それ、本当！？","ENG":"Do you mean that?!","TWN":"你、你是說真的吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"거짓말 아니지? 응?!","JPN":"ウソじゃないよね？　ね！？","ENG":"You're not lying to me, right?!","TWN":"沒有在騙我吧？嗯？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"날 도와서 몇 가지 일만 해결해준다면 말이지.","JPN":"私を手伝い、いくつかの仕事を解決してくれればな。","ENG":"Only if you help me solve a few things.","TWN":"……如果你能幫我解決幾件小事的話。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"몇 가지… 일이라고…?","JPN":"いくつかの……仕事……？","ENG":"A few... things...?","TWN":"幾件……小事……？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"처음 봤을 땐 좀 놀랐어.","JPN":"初めて会った時にはちょっと驚いた。","ENG":"I was taken aback when I first saw you, you know.","TWN":"第一次見到你還蠻讓我吃驚的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나 같은 천재를 로터스 같은 벽지에 처박아 둔 최고관리자란 인간은 뇌만큼 머리도 쬐끄맣고 털도 무성한 유인원인 줄 알았는데…","JPN":"私みたいな天才をロータスのような僻地に閉じ込めた最高管理者って人間は、低能で毛むくじゃらの類人猿だと思ってたんだけど……","ENG":"I was sure that this Supreme Administrator who cooped up a genius like me in Lotus was a small-brained and hairy ape...","TWN":"竟然把我這樣的天才關在洛德斯這種鳥不拉屎的地方，我還以為最高管理者會是個大腦發育不全的猿人呢……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"실물은 제법 멀쩡해서 말이야.","JPN":"実物は結構まともなんだね。","ENG":"But you looked pretty normal in person.","TWN":"沒想到真人還蠻正常的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"사진으로 봤을 땐 말끔하던데, 지금은 자기관리를 안 하는 건가?","JPN":"写真で見た時は清純な印象だったが、今は自分にずいぶんなおざりなんだな？","ENG":"You looked neat in the picture, but are you not taking care of yourself now?","TWN":"呵呵……你照片上看起來很乾淨的，現在是不打理自己了嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"사무실에서 거의 나오는 일이 없다고 들었는데. 걱정했던 것보단 건강해 보여서 다행이군.","JPN":"事務室からほとんど出ないと聞いた。心配していたが元気そうで何よりだ。","ENG":"I heard you rarely leave the office. I was worried, but I'm glad to see that you look healthier than I thought.","TWN":"我聽說你幾乎不出辦公室，還有點擔心你的健康呢。現在一看真是太好了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"난 연구원으로 지원해서 관리국에 온 거야!","JPN":"私は研究員に志願して管理局に来たの！","ENG":"I joined the Administration by applying as a researcher!","TWN":"我是以研究員的身份申請加入管理局的！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그런 날 멋대로 시니어 자리에 앉혀 놓고서 이젠 정장까지 강요하는 거라면, 때려치고 말지.","JPN":"なのに私を勝手にシニアにして、そのうえ服装まで口を出すなら私は仕事をやめるよ。","ENG":"But then, you put me in this Senior position and now you're forcing me to wear a suit? I'd rather quit.","TWN":"隨便讓我當Senior就算了，現在還要強迫我穿套裝的話，我就不幹了！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신이… 날 걱정한다고?","JPN":"あなたが……私を心配してたって？","ENG":"You... were worried about me?","TWN":"你在……擔心我？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 날 이런 망령 들린 도시의 책임자로 앉혀 놓고 코빼기도 안 비쳤으면서. 내가 그 말을 믿을 것 같아?","JPN":"フン、私をこんな亡霊都市の責任者にしておいて姿も見せなかったくせに。私がそんな言葉を信じると思う？","ENG":"Hmph. You think I'll believe a word that comes out of your mouth after you put me in charge of this haunted city and never even bothered to visit once?","TWN":"哼，把我扔到這個鬼城市裡當管理者，自己卻跑得連個人影都不見。你覺得我會相信你的關心？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래서, 내가 해야 하는 일이라는 게 뭔데?","JPN":"それで、私の仕事って何なの。","ENG":"So? What kind of work are we talking about?","TWN":"所以呢……？我要做的事情是什麼？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"얼마 전, 마왕이 한 차례 현실로 침입을 시도했네.","JPN":"つい最近のことだが、魔王が現実への侵入を試みたんだ。","ENG":"A few days ago, a Demon Lord attempted to invade the Normalside.","TWN":"不久前，魔王曾試圖入侵現實世界。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"직접 보진 않았어도, 소식은 접했겠지.","JPN":"直接見ていなくても、話は聞いているだろう。","ENG":"I'm sure you've heard about it, even if you didn't see it for yourself.","TWN":"即使沒親眼見過，你也應該聽說過了吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"모를 수가 없지. 차원계면을 뚫고 하늘에서 눈알이 튀어나오는 도시괴담 같은 일이 실제로 벌어졌는데.","JPN":"知らないわけないでしょ。次元界面を貫いて空から目玉が出てくる都市伝説みたいなことが実際に起きたんだからね。","ENG":"Everyone knows about that. An eyeball appeared in the sky through the dimension surface like it was some kind of urban legend.","TWN":"我知道。就像是都市怪談一樣，天空中出現了穿越次元介面而來的巨大眼球。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"사태 수습은 커녕 아직 사망자 집계도 못 끝낸 실정이라고.","JPN":"事態を治めるどころか、まだ死者の数も全部集計できてないよ。","ENG":"We haven't even finished counting how many casualties there were, let alone control the situation.","TWN":"別說是控制局勢了，我們到現在連死亡人數都還沒統計完全。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그건 전조에 지나지 않아.","JPN":"だが、それは前兆に過ぎない。","ENG":"But it was just the beginning.","TWN":"但那只是前兆而已。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마왕의 온전한 힘이 현실을 침범하게 되면, 그땐 하늘을 바라보지 않는 것 정도로는 대처할 수 없게 되겠지.","JPN":"魔王の真の力が現実を侵略すれば、その時は空を見上げない程度では対処できなくなるぞ。","ENG":"If the Demon Lord invades the Normalside with her full power, then not looking up at the sky won't be enough.","TWN":"如果魔王的完整力量入侵現實的話，那時就不是光憑不看天空就能應對的了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐? 그게 고작 전조라고…? 당신네 사람들이 어떻게든 해결한 거 아니었어?","JPN":"は？　あれで前兆だったの……？　あなたたちが何とか解決したんじゃないの？","ENG":"What? That's just the beginning...? But I thought your people handled it somehow.","TWN":"什麼……？那只是個前兆而已……？魔王不是已經被你們解決了嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"급한 불은 끄기 위한 임시방편이었네.","JPN":"急場をしのぐ手段に過ぎなかったのだよ。","ENG":"That was just a temporary measure.","TWN":"這只是為了應急的權宜之計。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 방편조차 얼마나 버텨줄지 모르는 실정이고.","JPN":"それも、どのくらい耐えてくれるかわからない。","ENG":"And there's no knowing how much more time we have.","TWN":"就連那個方法也不知道能撐多久。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼… 앞으로 그 마왕이란 괴물과 전면전을 벌여야 하는 건가?","JPN":"じゃあ……これからその魔王って化け物と全面戦争をしないといけないわけ？","ENG":"Then... are you going to fight head-on against that monster you call a Demon Lord?","TWN":"那麼……接下來要和那個叫魔王的怪物全面開戰了嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 되겠지.","JPN":"そうなるだろうな。","ENG":"I guess so.","TWN":"我猜是那樣的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 마왕이 현실로 부상하게 되면, 승패가 정해지기 전에 세계가 먼저 무너지고 말 걸세.","JPN":"だが、魔王が現実に浮上すると、勝敗が決まる前に世界が先に崩壊してしまうはずだ。","ENG":"But if the Demon Lord emerges in the Normalside, the world will collapse even before we have a proper fight.","TWN":"但是如果魔王真的出現了，世界會在決出勝負之前就先瓦解。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니, 놈이 움직이기 전에 우리가 먼저 놈을 찾아 발을 묶어야 하네.","JPN":"だから、やつが動く前に私たちが先にやつを探し出して、足止めしないといけない。","ENG":"So, we must act preemptively before she does.","TWN":"所以，我們必須搶在那傢伙行動之前找到她，將她困住。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 당신이 말하는 제안이란 게…","JPN":"それで、あなたが言う提案って……","ENG":"So, what you're proposing is...","TWN":"所以說你的提議是……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"허수공간이나 다름없는 클리파 차원에서 마왕을 찾아는 것도 모자라 그 녀석을 멈추게 해달라는 거지?","JPN":"虚数空間と変わらないクリファ次元で魔王を探し出して、さらにそいつの身動きを止めてくれってことでしょ？","ENG":"for me to find the Demon Lord within the Qlipha Dimension, which is basically the imaginary space, and stop her?","TWN":"讓我想個辦法在無異於虛數空間的逆卡巴拉次元中，不僅僅是要找到魔王，還要阻止那傢伙，是吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그거 진짜 터무니 없는 요구인 거 알아?","JPN":"それ、マジでとんでもない要求だってわかってる？","ENG":"Do you know how ridiculous your request is?","TWN":"你知道那是天方夜譚吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"불가능하다면 어쩔 수 없군.","JPN":"不可能なら仕方ない。","ENG":"If it's impossible, then there is nothing we can do.","TWN":"如果不可能，那也沒辦法了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"설계도 건은 없던 얘기로 하지. 시간을 빼앗아서 미안하네.","JPN":"設計図の話はなかったことにしよう。時間を無駄にさせてしまってすまない。","ENG":"Forget about the blueprint. I'm sorry for wasting your time.","TWN":"設計圖的事就當沒說過吧。抱歉佔用了你的時間。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잠깐 기다려…!","JPN":"ちょっと待って……！","ENG":"Hold on now...!","TWN":"等一下……！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그 방법이 터무니없댔지, 다른 방법이 없다곤 안 했거든?","JPN":"その方法が無茶なだけで、他の方法がないとは言ってないんだけど？","ENG":"I said that what you're asking is ridiculous. I didn't say that there weren't any alternatives.","TWN":"我只是說那個辦法不保險，又沒說沒有其他方法？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"듣고 있네.","JPN":"聞いている。","ENG":"I'm listening.","TWN":"……我在聽。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그러니까… 마왕이라는 폭주 기관차를 멈출 수 없다면, 마왕이 향하는 길목에 전환기를 설치해서 선로를 바꾸는 거야.","JPN":"だから……魔王という暴走機関車を止められないなら、魔王が向かう進路に転換器を設置して線路を変えるんだよ。","ENG":"So... if we can't stop the runaway train called Demon Lord, we install a switch on the path and change the track.","TWN":"所以說……如果無法阻止魔王這輛暴走的火車，那就在她前進的路上裝上道岔，改變軌道好了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"현실이 아닌 다른 이면세계로.","JPN":"現実じゃない、他の裏世界に。","ENG":"We'll change her destination from the Normalside to another Counterside.","TWN":"讓她前往另一個非現實的異界。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮은 대안이군.","JPN":"悪くない代案だな。","ENG":"That's a good alternative.","TWN":"這是個不錯的替代方案。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 일을 맡게 되면 자네의 행정업무는 그라운드 원에서 지원해주기로 했네.","JPN":"この仕事を引き受ければ、君の行政業務はグラウンド・ワンで支援してくれることになる。","ENG":"If you take on this job, Ground One will assist with your administrative duties here.","TWN":"如果接下這項工作，你的行政事務今後將由G1支援。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"해볼 수 있겠나?","JPN":"できるか？","ENG":"Will you do it?","TWN":"願意試試看嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"마왕이 클리파 차원을 이용하는 방식이 그림자의 차원 부상 원리와 비슷하다면, 차원함선을 개조해서 의도적으로 경로를 비트는 것도 이론상 가능해.","JPN":"魔王がクリファ次元を利用する方法がシャドウの次元浮上の原理と似ているなら、次元艦船を改造して意図的に経路をねじ曲げることだって理論上はできるよ。","ENG":"If the Demon Lord uses the Qlipha Dimension similar to how Shadows emerge to the Normalside, it's theoretically possible to change her route by modifying a dimensional ship.","TWN":"……如果魔王利用逆卡巴拉次元的方式與暗影躍出的原理相似，那麼理論上也可以透過特殊改造的次元艦船來扭轉她的路徑……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"제안을 받아들였다고 생각해도 되겠나?","JPN":"提案を引き受けたと解釈してもいいのかね？","ENG":"Can I assume that you have accepted the offer?","TWN":"我可以認為你已經接受提議了嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"어디까지나 이론이긴 하지만, 적어도 시도해 볼 가치는 있겠지.","JPN":"あくまでも理論なんだけど、少なくとも試してみる価値はある。","ENG":"It's all hypothetical, but it's worth a shot.","TWN":"雖然這只是理論，但至少值得一試。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"못하면 다 죽는다는데 뭐.","JPN":"上手くいかなかったらみんな死ぬんだしさ。","ENG":"If we fail, well, then we'll all die anyway.","TWN":"反正做不到的話，大家都會死吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 그 건은 이졸데 양에게 맡기도록 하겠네.","JPN":"では、その件はイゾルデ君に任せよう。","ENG":"Then, I'll leave this task to you, Isolde.","TWN":"好，那麼這件事就交給你了，伊索德。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐…? 그렇게 툭 던져 놓고 그냥 간다고?","JPN":"は……？　あとは丸投げして帰るつもり？","ENG":"What...? You're just going to leave?","TWN":"什麼……？你又要這樣隨便扔下擔子然後走人嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"한동안 로터스에 머무는 거 아니었어? 딱히 날 돕진 않더라도 잘 하는지 감시한다거나…","JPN":"しばらくロータスにいるんじゃなかった？　別に私のことを手伝わなくても、ちゃんとやってるか監視するとか……","ENG":"I thought you were staying in Lotus for a while. Even if you didn't help me, I thought you'd monitor me if I'm doing my job...","TWN":"我還以為你要在洛德斯待一陣子……？即使不來幫忙，也可以監視我做得好不好啊……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"원래라면 나도 자네 연구를 도울 생각이었지만 더 급한 볼일이 생겼어.","JPN":"本来、私も君の研究を手伝うつもりだったが、さらに急を用することができてね。","ENG":"I was planning to help with your research, but a more urgent matter came up.","TWN":"本來我也打算協助你研究的，但有更緊急的事情發生了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리 회사의 새로운 직원과 함께 예정에 없던 출장을 가야 할 것 같아.","JPN":"会社の新しい職員とともに、予定になかった出張に行かなければならない。","ENG":"I think I'll have to go on an unscheduled business trip with a new employee at our company.","TWN":"我好像得和我們公司的新進員工一起去一趟計畫外的出差。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"회사 직원…","JPN":"会社の職員……","ENG":"A company employee...","TWN":"公司員工……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"저기. 그러고보니 당신이 운영한다던 태스크포스.","JPN":"ねえ。そういえば、あなたが運営してるタスクフォース。","ENG":"Um, the TASKFORCE that you operate.","TWN":"對了，說起來你經營的那個特遣勢力。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"거기에 있는 당신 부하들은 믿을만해?","JPN":"そこにいるあなたの部下って、信頼できる？","ENG":"Is everyone there trustworthy?","TWN":"那裡的員工都可靠嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"물론이지. 난 믿을 수 있는 사람만 채용한다네.","JPN":"もちろんさ。私は信頼できる人だけを採用しているからな。","ENG":"Of course. I only hire people I can trust.","TWN":"當然。我只聘請值得信賴的人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"바쁘니 용건부터 말해주겠나?","JPN":"忙しいんだ、用件から話してくれないか？","ENG":"I'm in a rush, so could you get to your point?","TWN":"咳咳……我現在確實有點忙，能直接說重點嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래? 그렇단 말이지?","JPN":"そう？　そうだよね。","ENG":"Oh? Is that so?","TWN":"是嗎？是這樣啊？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"저기, 그럼 당신 회사에 의뢰 하나만 해도 돼?","JPN":"あのさ。じゃあ、あなたの会社に1つだけ依頼してもいい？","ENG":"Well, do you mind if I request something from your company?","TWN":"那個，可以委託你們公司一個任務嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥… 알았어. 보채지 않아도 말할 거야.","JPN":"フン……わかったよ。急かさなくても話すから。","ENG":"Hmph... fine. I'll say it, so don't make a fuss.","TWN":"哼……好吧。不用你催，我會說的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"으음… 그러니까…","JPN":"うーん……えっと……","ENG":"Mm... So...","TWN":"嗯……所以說……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"사람을 좀 찾아줘! 당신 부하들을 이용해서 말이야!","JPN":"ちょっと人を探して！　あなたの部下を使って！","ENG":"I want you to help me find someone! Using your people, that is!","TWN":"幫我找個人！用你的員工去找！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리 거래는 이터니움 드라이브의 설계를 제공한 시점에서 성사된 걸로 알았는데.","JPN":"私たちの取引はエタニウムドライブの設計を提供した時点で成立したと思ったんだが。","ENG":"I thought our deal was done when I provided the Eternium Drive blueprint to you.","TWN":"我以為我們的交易在提供永恆之金驅動器設計圖的那一刻就已經結束了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"클리파 차원을 넘나드는 괴물을 멈춰 세우려면, 차원도약의 원리를 알아야 해.","JPN":"クリファ次元を行き来する化け物を止めるためには、次元跳躍の原理を知らないとダメだよ。","ENG":"In order to stop a monster that can traverse in and out of the Qlipha Dimension, we need to know the principles of the dimension jump.","TWN":"要阻止可以穿過逆卡巴拉次元的怪物，就必須了解次元跳躍的原理。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나한테 이 일을 맡기러 왔을 때부터, 어차피 설계는 제공해줄 생각이었던 거잖아?","JPN":"私にこの仕事を任せるために来た時から、どうせ設計は提供してくれるつもりだったんでしょ？","ENG":"You were already planning to provide me with the blueprint the moment you came here to give me this job, didn't you?","TWN":"你來找我的時候，就已經打算提供設計圖了吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일리 있는 지적이군.","JPN":"一理ある指摘だな。","ENG":"You have a point.","TWN":"說的有道理。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 왜 굳이 내 회사 직원들에게 맡기려는 거지? 웬만한 일은 자네 휘하의 사람들을 움직여도 될 텐데.","JPN":"だが、どうして私の会社の職員に任せたいんだ？　通常の仕事なら君の部下を動かせば済むはずだ。","ENG":"But why do you wish to leave it to my employees? I'm sure you have people under you who you can order at your will.","TWN":"但是為什麼非要交給我公司的員工呢？一般的事情讓你手下的人去做就可以了吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 관계자가 엮이면 곤란해지는 일이야.","JPN":"管理局の関係者が関わると困るからだよ。","ENG":"It will get complicated if anyone from the Administration gets involved.","TWN":"因為讓管理局的人牽扯進來會變得更麻煩。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"소문이 나서도 안되고, 실패해서도 안되니 용병을 쓸 수도 없어.","JPN":"ウワサになっても、失敗してもダメだから傭兵を使うこともできないんだ。","ENG":"I can't have rumors spreading, and failure isn't an option, so mercenaries are out of the picture as well.","TWN":"不能讓消息走漏，也不能失敗，所以不能使用　傭兵。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"클리포트 게임의 최전선까지 나가서 살아 남은 당신 부하들이라면… 실력이나 신뢰도 면에선 충분할 거라 판단했거든.","JPN":"クリフォトゲームの最前線まで行って生き残ったあなたの部下なら……実力と信頼性の面で十分だと判断したから。","ENG":"But if it's your people, who went to the forefront of the Qliphoth Game and came back... I thought they'd be both trustworthy and skilled.","TWN":"能在逆卡巴拉遊戲最前線生存下來的員工……我認為他們在實力和信賴度方面都足夠了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"찾고 있는 사람은 납치를 당한 건가?","JPN":"探している人は、拉致されたのか？","ENG":"Has this person you're looking for been kidnapped?","TWN":"你在找的人是被綁架了嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그건…","JPN":"それは……","ENG":"Well…","TWN":"我……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"납치라고 단정 지을 순 없어. 하지만 그 사람에게 나쁜 일이 생긴 것만은 확실해.","JPN":"拉致かは断定できない。でも、あの人に良くないことが起きたのは確かだよ。","ENG":"I don't think we can conclude that he's been kidnapped. But I'm sure something bad has happened to him.","TWN":"不能斷定是綁架。但我可以確定那個人遇到了不好的事情。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 사람이 누구지?","JPN":"その人は誰だ？","ENG":"And who is this person?","TWN":"那個人是誰？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신도 나만큼 잘 아는 사람이야.","JPN":"あなたもよく知ってる人だよ。","ENG":"It's someone that you know as well as I do.","TWN":"一個你也知道的人……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"시니어 잭슨.","JPN":"シニア・ジャクソン。","ENG":"Senior Jackson.","TWN":"Senior傑森。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잭슨이 사라졌다고?","JPN":"ジャクソンが消えたのか？","ENG":"Jackson's gone missing?","TWN":"傑森……失蹤了？"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"벌써 일주일째 연락이 안돼. 챔버의 관계자들도 실종 사실은 당일날 파악했지만 행방은 몰라.","JPN":"もう1週間も連絡が取れない。チェンバーの関係者たちも失踪はその日のうちに把握したけど、行方はわからない。","ENG":"It's been a week since I lost contact. Chamber officials learned about his disappearance on the day, but they haven't been able to figure out his whereabouts.","TWN":"已經失去聯絡一週了。雖然強巴那邊當天就發現了他失蹤的事實，但目前仍然沒有找到行蹤。"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"전에도 몇 번씩 말 없이 사라지긴 했지만 일주일이나 소식이 끊겼던 적은 없어.","JPN":"何も言わずに消えたことは何度かあったけど、1週間も連絡が途絶えたことはなかった。","ENG":"He's been known to go off grid a few times, but his being radio silent for a week is unprecedented.","TWN":"之前也有幾次不打招呼就消失的情況，但從來沒有像這次一樣久。"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잭슨의 행방에 대해선 여전히 단서가 없는 건가?","JPN":"ジャクソンの行方については、相変わらず手がかりがないのか？","ENG":"There are no clues to his whereabouts?","TWN":"關於傑森的下落，有什麼其他線索嗎？"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아, 단서라면 있어. 바로 어젯밤, 잭슨 씨의 송신기가 작동하면서 위치 신호가 기록에 남았거든.","JPN":"あ、手がかりならあるよ。昨日の夜、ジャクソンさんの送信機が作動して位置信号が記録に残ってるから。","ENG":"Oh, there is one. Last night, Mr. Jackson's transmitter turned on and it left a record of his location.","TWN":"啊，如果是線索的話……就在昨晚，傑森的發射器啟動了，位置訊號被記錄下來了。"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 좌표는… 북방합의체의 영토로군.","JPN":"この座標は……北方合意体の領土だな。","ENG":"These coordinates... It's within the Northern Union's territory.","TWN":"這個座標是……北方和議會的領土。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하지만 아주 잠깐 동안 켜졌을 뿐이고, 연락이 닿은 적도 없어서 본인이라 확신할 순 없어.","JPN":"でも本当に一瞬作動しただけで、連絡は取れてないから本人だとは確信できない。","ENG":"It was only on for a split second. We couldn't make contact, so we can't be sure if it's even him.","TWN":"但是只亮了一下，而且也沒有聯絡上，所以不能確定是本人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"애초에 관리국의 시니어가 무슨 이유로 위험을 무릅쓰고 적진 한복판으로 혼자 가겠어?","JPN":"そもそも管理局のシニアがどうして危険を冒して敵陣のど真ん中に1人で行くんだよ？","ENG":"Why would an Administration Senior take the risk of going alone into the middle of enemy territory?","TWN":"管理局的Senior為什麼要冒險獨自前往敵方領土中央……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자초지종은 본인에게 직접 물어보는 편이 빠르겠지.","JPN":"詳しい話は本人から直接聞いた方が早いだろう。","ENG":"It'll be quicker to ask him directly.","TWN":"事情的來龍去脈直接問本人會更快吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"너무 걱정 말게. 자네가 선로전환기를 준비할 동안 내가 잭슨을 찾아볼 테니.","JPN":"あまり心配するな。君が線路転換器を準備している間に、私がジャクソンを探そう。","ENG":"Don't worry so much. While you make the track switcher, I'll look for Jackson.","TWN":"不用太擔心。在你準備變軌器的時候，我會去找他的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"정말? 고마워.","JPN":"本当？　ありがとう。","ENG":"Really? Thanks.","TWN":"真的嗎？謝謝。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"반쯤 억지부린 거라 진짜로 부탁을 들어줄 줄은 몰랐는데…","JPN":"無理強いしたから、本当に聞いてくれるとは思わなかったけど……","ENG":"I know I was being stubborn, but I didn't think you'd actually say yes...","TWN":"本來是有點強人所難的請求，沒想到你真的會答應……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"착각하지 말게.","JPN":"勘違いしないでくれ。","ENG":"Don't be mistaken.","TWN":"別搞錯了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"응…?","JPN":"うん……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네 부탁 때문이 아니야.","JPN":"君に頼まれたからではない。","ENG":"It's not because you asked.","TWN":"這不是因為你的請求。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아랫직원에게 문제가 생겼다면 사장이 발벗고 나서는 게 당연하잖나.","JPN":"部下の職員に問題が発生したなら、社長が一肌脱ぐのは当たり前のことさ。","ENG":"It's only natural for the boss to take action when one of his subordinates has a problem.","TWN":"如果下屬出了問題，老闆當然應該親自出馬全力以赴。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"사장…이라고?","JPN":"社長……って言った？","ENG":"Did you just call yourself... boss?","TWN":"老……闆？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"실례했군… 요즘은 이 호칭이 입에 붙어버려서 말이지.","JPN":"失礼……最近この呼び方が癖になってしまってね。","ENG":"My apologies... It seems that I've gotten a bit too fond of this title.","TWN":"失禮了……最近已經習慣這個稱呼了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"솔직히… 너무 무서워서 누굴 만날 엄두도 못 내고 있었어.","JPN":"正直……すごく怖くて誰かに会う気力も出せずにいたんだ。","ENG":"Honestly... I was too scared to meet anyone.","TWN":"說實話……我因為太害怕了，根本不敢見任何人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드에서 리하르트 아저씨가 당한 것처럼, 잭슨 씨마저 스완이란 녀석에게 당한 거라면…","JPN":"シャレードでリヒャルトのおじさんがやられたみたいに、ジャクソンさんまでスワンってやつにやられたんだったら……","ENG":"Just like what happened to Richard in Charade, if Swan got to Jackson as well...","TWN":"如果傑森也像理查叔叔一樣遇害了的話……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나도 언제든 그 타깃이 될 수 있다는 뜻이니까.","JPN":"私もいつかはそのターゲットになるって意味だから。","ENG":"That would mean that I could also become a target.","TWN":"那就表示我也隨時可能成為目標。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 심정, 충분히 이해하네.","JPN":"その心情は十分理解できる。","ENG":"I completely understand.","TWN":"那種心情，我完全理解。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일주일이 넘게 바깥 출입을 하지 않은 것도 그런 연유였군.","JPN":"1週間以上も外に出ていないのは、そんな理由だったのか。","ENG":"So that's why you refused to step out for over a week.","TWN":"你一個多星期沒出門也是這個原因吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그… 외출은 원래 거의 안 하긴 해.","JPN":"その……元々あんまり外には出ないんだ。","ENG":"Erm... I don't usually go out in the first place.","TWN":"那個……我本來就幾乎不出門。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 업무가 바쁘면 그럴 수도 있지.","JPN":"コホン、仕事が忙しいとそんなこともあるさ。","ENG":"Ahem. Perhaps you're too busy with work.","TWN":"咳咳……我明白，因為工作很忙嘛，這也情有可原。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래서. 잭슨을 찾으러 어떤 직원을 보낼 셈이야?","JPN":"それで。ジャクソンを探すのにどんな職員を送るつもり？","ENG":"So? Who are you sending to find Jackson?","TWN":"所以，你打算派哪個員工去找傑森？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좀 전에 말하지 않았나. 직접 발벗고 나서겠다고.","JPN":"さっき話しただろう？　私が一肌脱ぐと。","ENG":"I just said, I'm going to take action.","TWN":"剛才不是說了嗎？我會親自去。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마침 볼일이 있는 곳도 그 근처이고 말이지.","JPN":"ちょうど用事があるのもその周辺地域なんだ。","ENG":"It just so happens that I have business nearby.","TWN":"正好我要去的地方也在附近。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐어어어?!!!","JPN":"はあああ！！！？","ENG":"WHAAAAAT?!!!","TWN":"什麼啊啊啊啊？！！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신이 무슨 S급 카운터라도 돼? 무슨 배짱으로 그 위험한 곳을 직접 간다는 거야?!","JPN":"自分がS級カウンターとか言うつもり？　そんな危険なところに直接行くなんて、無茶にもほどがあるでしょ！！","ENG":"Do you think you're some Grade S Counter? What makes you think you can go to a dangerous place like that yourself?!","TWN":"你以為你是S級制裁者嗎？你憑什麼去那麼危險的地方？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"딱히 처음 있는 일도 아닐세. 관리국의 기반이 어느 정도 잡힐 때까진 물건 하날 구하려고 혼자 침식지대를 횡단하기도 했으니까.","JPN":"別に初めてのことでもない。ある程度管理局の基盤が整うまでは物資を探すために1人で侵食地帯を横断したりもしたからね。","ENG":"It's not the first time I've done it. Before the foundation of the Administration was established, I would cross Corrupted Areas alone to find a single item.","TWN":"其實也不是第一次了。在管理局穩定之前，我也會為了尋找某件東西獨自穿過侵蝕地區。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그런 식으로 살았으면서 어떻게 아직도 살아있는 건데?!","JPN":"そんな風に生きながら、どうやってここまで生き残れたの！？","ENG":"How are you even alive?!","TWN":"那樣的話，你怎麼還能活著？!"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"몸이 기억하고 반응하는 거지. 실패를 수도 없이 되풀이하다 보면 얻는… 초능력 같은 걸세.","JPN":"体が記憶して反応するのだ。数えきれないほどの失敗を繰り返していると得られる……超能力みたいなものさ。","ENG":"The body remembers and reacts. What I obtain after repeating countless failures is... a sort of superpower.","TWN":"身體會記住並做出反應。這是經過無數次失敗後獲得的……類似超能力的東西。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"죽어! 그런 무모한 짓을 하다가 실패하면 초능력을 얻는 게 아니라 보통 죽는다고!","JPN":"死ぬよ！　そんな無茶をして失敗したら、超能力を得るんじゃなくて普通は死ぬんだよ！","ENG":"No, people die! Doing something that reckless and failing doesn't grant people superpowers! People normally just DIE!","TWN":"不對！是會死！那種魯莽的事情，一旦失敗了，不是獲得超能力，而是會死的！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아니면 뭐, 당신 목숨은 몇 개씩이나 된다는 거야?","JPN":"それとも、あなたには命が何個もあるわけ？","ENG":"Or, what, do you have more lives than one?","TWN":"不然的話，你有好幾條命嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"비슷했지. 이젠 아니지만.","JPN":"似たようなものだ。今は違うが。","ENG":"Sort of. But not anymore.","TWN":"是有點類似……但現在不是了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"무, 무슨 뜻이야 그게.","JPN":"ど、どういう意味なんだよ、それ。","ENG":"W-what's that supposed to mean?","TWN":"什、什麼意思啊，那是？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래서? 대체 그 볼일이란 게 뭐길래 그래?","JPN":"それで？　その用事っていったい何？","ENG":"So? What business do you even have over there?","TWN":"所以？到底是什麼事讓你不得不去？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 책임 하에 있는 직원 한 명도,","JPN":"私の責任下にある職員の1人も、","ENG":"An employee of mine–","TWN":"我的其中一位員工……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 말한 곳과 비슷한 장소에서 실종된 것 같거든.","JPN":"君が言った場所と似たような場所で失踪したみたいだ。","ENG":"–seems to have also disappeared around the same place.","TWN":"她好像就是在你說的那個地方失蹤的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};